SELECT *
FROM support_packages
WHERE price BETWEEN 50 AND 100;

SELECT COUNT(*) 
FROM support_request_assignments 
WHERE agent_id = 1;

SELECT c.contract_id, c.customer_id, c.cancellation_date
FROM contracts AS c
WHERE c.cancellation_date IS NOT NULL AND c.cancellation_date < date('now');

SELECT COUNT(*) 
FROM support_request_assignments 
WHERE agent_id = (SELECT agent_id FROM support_agents WHERE agent_name = 'Alice Brown');

SELECT MAX(package_id) AS highest_package_id
FROM support_packages
WHERE package_name = 'Premier';

SELECT package_name 
FROM support_packages
WHERE price = (SELECT MAX(price) FROM support_packages);

SELECT access_id, contract_id, access_type, access_details
FROM priority_live_agent_access
WHERE access_type LIKE '%M-F%';

SELECT request_category, COUNT(*) as total_requests
FROM support_requests
GROUP BY request_category;

SELECT c.customer_id, c.customer_name, c.email, c.phone_number, c.customer_address, c.company_name, c.industry
FROM customers c
WHERE c.customer_id = (
    SELECT customer_id
    FROM contracts
    WHERE contract_id = (
        SELECT MAX(contract_id) 
        FROM contracts
    )
);
